import scala.util.Try


object Main extends App {
  val system = ActorSystem("Main")
  val materializer = Materializer(system)

  def handlePost(request: HttpRequest): Future[HttpResponse] =
    Http().singleRequest(request).flatMap { response =>
      println(s"Response: ${response}")

      // This is the most important part. We need to unpack the data from the request body.
      val content = Try{
        response.entity.toStrict(500)
      } match {
          case Success(_) => "Success"
          case Failure(ex) => s"Failure: ${ex}"
      }

      // Now we return the same response as before, but with the data from the request body.
      HttpResponse(status=response.status, entity=content)
    }

  def handleGet(request: HttpRequest): Future[HttpResponse] = {
    println(s"Request: ${request}")

    val response = Try{
      request.uri.path.split('/') match {
        case Array("one", "two") => 201
        case Array("one", "three") => 304

        // If the path is not one of these, we return a bad request (400) back to the client.
        case _ => 400
      }
    }.getOrElse(400)

    HttpResponse(status=StatusCodes(response))
  }

